// n8n Code node - форматуємо всі товари в JSON формат
const merged = []; 
for (const entry of items) {
  const payload = entry.json;
  let data = [];
  if (Array.isArray(payload)) {
    data = payload[0]?.data ?? payload;
  } else if (Array.isArray(payload.data)) {
    data = payload.data;
  }
  for (const { id, name, description } of data) {
    merged.push({ id, name, description });
  }
}
let jsonString = JSON.stringify(merged, null, 2);
return [
  {
    json: {
      count: merged.length,
      products_json: jsonString
    }
  }
];

// Безпечна обробка даних
try {
  const inputItems = items || [];
  const allItems = inputItems.map(item => item.json || item);
  console.log(`Processed ${allItems.length} items`);
  return [{
    json: {
      data: allItems,
      count: allItems.length
    }
  }];
} catch (error) {
  console.error('Error processing items:', error);
  return [{
    json: {
      data: [],
      error: error.message
    }
  }];
}

